// Structure definition
struct Numbers {
    int a;
    int b;
};

// Function that takes structure as parameter and returns sum
int addNumbers(struct Numbers n) {
    return n.a + n.b;
}

int main() {
    struct Numbers n;

    // Input two numbers
    scanf("%d", &n.a);
    scanf("%d", &n.b);

    // Call function and print sum
    printf("%d", addNumbers(n));

    return 0;
}

